31: const lut_ee = [6]u16{ 0x00EA, 0x1EBF, 0x1EC1, 0x1EC3, 0x1EC5, 0x1EC7 }; // ê
32: const lut_i = [6]u16{ 0x0069, 0x00ED, 0x00EC, 0x1EC9, 0x0129, 0x1ECB };
