348: // ── Exported API ─────────────────────────────────────────────────────
349: 
350: export fn state_size() usize {
351:     return @sizeOf(State);
352: }
353: 
354: export fn init_state(state: *anyopaque) void {
355:     const s: *State = @ptrCast(@alignCast(state));
356:     s.* = std.mem.zeroes(State);
357: }
358: 
359: export fn reset(state: *anyopaque) void {
360:     const s: *State = @ptrCast(@alignCast(state));
361:     s.* = std.mem.zeroes(State);
362: }
363: 
364: export fn backspace(state: *anyopaque) u8 {
365:     const s: *State = @ptrCast(@alignCast(state));
366:     if (s.len == 0) return 0;
367:     s.len -= 1;
368:     // Clear the removed span
369:     s.spans[s.len] = std.mem.zeroes(Span);
370:     // If all spans removed, reset mode
371:     if (s.len == 0) s.mode = 0;
372:     return 1;
373: }
