375: export fn add(state: *anyopaque, char_code: u16) u8 {
376:     const s: *State = @ptrCast(@alignCast(state));
377: 
378:     // Only handle ASCII range
379:     if (char_code > 127) {
380:         reset(state);
381:         return 0;
382:     }
383:     const ch: u8 = @intCast(char_code);
384: 
385:     // Non-alphanumeric → reset and passthrough
386:     if (!isAlpha(ch)) {
387:         reset(state);
388:         return 0;
389:     }
390: 
391:     const lo = toLower(ch);
392:     const is_upper = ch >= 'A' and ch <= 'Z';
393:     const flags: u8 = if (is_upper) 0x01 else 0x00;
394: 
395:     // ── LITERAL mode: just append ──
396:     if (s.mode == 1) {
397:         if (!appendSpan(s, ch, 0, 0, flags | 0x02)) return overflowReset(s);
398:         return 1;
399:     }
400: 
401:     // ── Check if first char triggers LITERAL mode ──
402:     if (s.len == 0) {
403:         if (lo == 'f' or lo == 'j' or lo == 'w' or lo == 'z') {
404:             enterLiteral(s);
405:             if (!appendSpan(s, ch, 0, 0, flags | 0x02)) return overflowReset(s);
406:             return 1;
407:         }
408:         // First char: just append as a regular span
409:         if (!appendSpan(s, ch, 0, 0, flags)) return overflowReset(s);
410:         return 1;
411:     }
412: 
413:     // ── dd → đ ──
414:     if (lo == 'd') {
415:         // Look for last 'd' span without modifier
416:         if (s.len > 0) {
417:             const last_idx = s.len - 1;
418:             const last = &s.spans[last_idx];
419:             if (toLower(last.base) == 'd' and last.modifier == 0) {
420:                 // Cancellation: if already đ, undo
421:                 if (last.modifier == 'd') {
422:                     // Already handled above: modifier is 0 here
423:                     unreachable;
424:                 }
425:                 last.modifier = 'd';
426:                 return 1;
427:             }
428:         }
429:         // Regular d consonant
430:         if (!appendSpan(s, ch, 0, 0, flags)) return overflowReset(s);
431:         autoFillUO(s);
432:         return 1;
433:     }
434: 
435:     // ── Doubled vowel modifier: aa→â, ee→ê, oo→ô ──
436:     if (lo == 'a' or lo == 'e' or lo == 'o') {
437:         // Check if previous span is the same base vowel with no modifier
438:         if (s.len > 0) {
439:             const last_idx = s.len - 1;
440:             const last = &s.spans[last_idx];
441:             if (toLower(last.base) == lo and last.modifier == 0 and spanIsVowel(last.*)) {
442:                 // Cancellation check: if modifier already equals lo, strip it
443:                 // (can't happen here since modifier == 0)
444:                 last.modifier = lo;
445:                 return 1;
446:             }
447:         }
448:     }
449: 
450:     // ── w modifier ──
451:     if (lo == 'w') {
452:         // Look for target vowel: last a/o/u in the word
453:         var target: ?u8 = null;
454:         var i: u8 = 0;
455:         while (i < s.len) : (i += 1) {
456:             const b = toLower(s.spans[i].base);
457:             if (b == 'a' or b == 'o' or b == 'u') {
458:                 target = i;
459:             }
460:         }
461:         if (target) |ti| {
462:             const sp = &s.spans[ti];
463:             if (sp.modifier == 'w') {
464:                 // Cancellation: same modifier pressed again → enter literal
465:                 enterLiteral(s);
466:                 if (!appendSpan(s, ch, 0, 0, flags | 0x02)) return overflowReset(s);
467:                 return 1;
468:             }
469:             if (sp.modifier != 0) {
470:                 // Already has a different modifier, can't apply w
471:                 // Treat w as a regular character → literal
472:                 enterLiteral(s);
473:                 if (!appendSpan(s, ch, 0, 0, flags | 0x02)) return overflowReset(s);
474:                 return 1;
475:             }
476:             sp.modifier = 'w';
477:             // Re-apply tone placement since modified vowel changed
478:             const ct = currentTone(s);
479:             if (ct != 0) applyTone(s, ct);
480:             return 1;
481:         }
482:         // No target vowel: if at start or no vowels, enter literal
483:         enterLiteral(s);
484:         if (!appendSpan(s, ch, 0, 0, flags | 0x02)) return overflowReset(s);
485:         return 1;
486:     }
487: 
488:     // ── Tone marks: s, f, r, x, j ──
489:     if (lo == 's' or lo == 'f' or lo == 'r' or lo == 'x' or lo == 'j') {
490:         const r = computeRegions(s);
491:         if (r.has_nucleus) {
492:             const ct = currentTone(s);
493:             if (ct == lo) {
494:                 // Cancellation: same tone pressed again → strip tone, enter literal
495:                 enterLiteral(s);
496:                 if (!appendSpan(s, ch, 0, 0, flags | 0x02)) return overflowReset(s);
497:                 return 1;
498:             }
499:             applyTone(s, lo);
500:             return 1;
501:         }
502:         // No nucleus vowels: treat as consonant
503:         if (!appendSpan(s, ch, 0, 0, flags)) return overflowReset(s);
504:         return 1;
505:     }
506: 
507:     // ── z: tone reset or literal ──
508:     if (lo == 'z') {
509:         const ct = currentTone(s);
510:         if (ct != 0) {
511:             // Remove tone from all vowels
512:             var i: u8 = 0;
513:             while (i < s.len) : (i += 1) {
514:                 if (spanIsVowel(s.spans[i])) {
