516:                 }
517:             }
518:             return 1;
519:         }
520:         // No tone to reset → enter literal
521:         enterLiteral(s);
522:         if (!appendSpan(s, ch, 0, 0, flags | 0x02)) return overflowReset(s);
523:         return 1;
524:     }
525: 
526:     // ── Vowels ──
527:     if (isVowel(lo)) {
528:         if (!appendSpan(s, ch, 0, 0, flags)) return overflowReset(s);
529:         // Re-apply tone placement after adding a vowel
530:         const ct = currentTone(s);
531:         if (ct != 0) applyTone(s, ct);
532:         return 1;
533:     }
534: 
535:     // ── Consonants ──
536:     if (!appendSpan(s, ch, 0, 0, flags)) return overflowReset(s);
537:     autoFillUO(s);
538:     return 1;
539: }
