541: export fn get_composed_utf16(state: *anyopaque, buf: [*]u16, buf_len: u16) u16 {
542:     const s: *State = @ptrCast(@alignCast(state));
543:     var pos: u16 = 0;
544: 
545:     var i: u8 = 0;
546:     while (i < s.len) : (i += 1) {
547:         if (pos >= buf_len) return 0xFF; // buffer overflow
548: 
549:         const sp = s.spans[i];
550: 
551:         // Literal spans: emit raw base character
552:         if (sp.flags & 0x02 != 0) {
553:             buf[pos] = @intCast(sp.base);
554:             pos += 1;
555:             continue;
556:         }
557: 
558:         const cp = lookupCodepoint(sp.base, sp.modifier, sp.tone);
559:         buf[pos] = cp;
560:         pos += 1;
561:     }
562: 
563:     return pos;
564: }

